data.content:
**MSTest does have comparison assertions** — they were added in MSTest 3.x. Here's what's available and how to apply them to your `ScoreCalculator`:

### Comparison Assertions

```csharp
Assert.IsGreaterThan(lowerBound, actual);
Assert.IsLessThan(upperBound, actual);
Assert.IsInRange(actual, low, high);
```

### Example Tests for Your Code

```csharp
[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        Assert.AreEqual(expected, _calc.CalculatePercentage(correct, total));
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInRange()
    {
        double result = _calc.CalculatePercentage(3, 4);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.99, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.99, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.99, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.99, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_WithinMax_ReturnsScaled()
    {
        double result = _calc.NormalizeScore(40, 80);
        Assert.AreEqual(50.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        double result = _calc.NormalizeScore(120, 100);
        Assert.IsGreaterThan(100.0, 120.0);   // raw > max
        Assert.AreEqual(100.0, result);        // but result is clamped
    }

    [TestMethod]
    public void NormalizeScore_Result_IsNonNegative()
    {
        double result = _calc.NormalizeScore(0, 50);
        Assert.IsGreaterThan(-1.0, result);  // result >= 0
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }
}
```

### Key Takeaways

| Assertion | Use for |
|---|---|
| `Assert.IsInRange(actual, low, high)` | Percentage is within 0–100 |
| `Assert.IsGreaterThan(bound, actual)` | Score exceeds a minimum |
| `Assert.IsLessThan(bound, actual)` | Score stays below a ceiling |
| `Assert.ThrowsExactly<T>(…)` | Invalid input guard clauses |
| `Assert.AreEqual(expected, actual)` | Exact boundary values (89.99 → "B") |

Use `IsInRange`/`IsGreaterThan`/`IsLessThan` for range validation, and `DataRow` with `AreEqual` for exhaustive boundary-value coverage at grade thresholds. These require **MSTest 3.x+**.
